1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_NUMERATOR = 11;
26	const FIRST_INSURANCE_DENOMINATOR = 10;
27	const PROCESSING_FEE = 5;
28	
29	const COMPONENT_PREMIUM = 25;
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	const componentBasePremium = (count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
36	
37	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
38	
39	const countByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const componentTotal = (items: Item[]): number =>
46	  [...countByType(items.filter(isComponent)).values()].reduce(
47	    (sum, count) => sum + componentBasePremium(count),
48	    0,
49	  );
50	
51	const basePremium = (items: Item[]): number => {
52	  const mainTotal = items
53	    .filter((item) => !isComponent(item))
54	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
55	  return mainTotal + componentTotal(items);
56	};
57	
58	const quotePremium = (items: Item[]): number => {
59	  const base = basePremium(items);
60	  const withFirstInsurance =
61	    (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
62	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
63	};
64	
65	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
66	  const results = scenario.steps.map((step) => ({
67	    premium: quotePremium(step.items),
68	  }));
69	  return { results };
70	};
